    routeSlug: "102-binary-tree-level-order-traversal",
    summary: "Given the root of a binary tree, collect each node's value grouped by depth, returning a list of lists where each inner list contains all values at that level from left to right.",
    approach: "- Use a **BFS queue** initialized with the root; each iteration processes exactly one level at a time.\n- Before dequeuing, snapshot the current queue size — this tells us exactly how many nodes belong to the current level.\n- Dequeue that many nodes, record their values, and enqueue their non-null children for the next pass.\n- Because BFS visits nodes in breadth-first order, each snapshot naturally corresponds to one complete level.",
    code: "#include <vector>\n#include <queue>\nusing namespace std;\n\n// TreeNode definition (provided by LeetCode)\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode* l, TreeNode* r) : val(x), left(l), right(r) {}\n};\n\nclass Solution {\npublic:\n    vector<vector<int>> levelOrder(TreeNode* root) {\n        vector<vector<int>> result;\n        if (!root) return result;\n\n        queue<TreeNode*> q;\n        q.push(root);\n\n        while (!q.empty()) {\n            // Snapshot the number of nodes at this level before expanding\n            int levelSize = static_cast<int>(q.size());\n            vector<int> level;\n            level.reserve(levelSize);\n\n            for (int i = 0; i < levelSize; ++i) {\n                TreeNode* node = q.front();\n                q.pop();\n                level.push_back(node->val);\n\n                // Enqueue children for the next level\n                if (node->left)  q.push(node->left);\n                if (node->right) q.push(node->right);\n            }\n\n            result.push_back(std::move(level));\n        }\n\n        return result;\n    }\n};\n",
    timeComplexity: "O(n)",
    spaceComplexity: "O(n)",
