    summary: "Given a binary tree where each node holds an integer value, find the maximum sum achievable by any path — where a path is any sequence of adjacent nodes with no node visited twice and no direction constraint.",
    approach: "- Use a post-order DFS that, at each node, computes the best \"arm\" (one-sided path that can extend upward to the parent) and updates a global answer.\n- The arm value is `max(0, left_arm, right_arm) + node->val`; clamping with 0 discards subtrees that would drag the sum negative.\n- The path that peaks at this node connects both arms: `left_arm + node->val + right_arm`; compare this against the running global max.\n- Return only the single-arm value upward so the caller can legally extend the path in one direction.",
    code: "#include <algorithm>\n#include <climits>\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode* left;\n    TreeNode* right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode* left, TreeNode* right)\n        : val(x), left(left), right(right) {}\n};\n\nclass Solution {\n    int ans = INT_MIN;\n\n    // Returns the best single-arm gain this subtree can contribute upward.\n    int dfs(TreeNode* node) {\n        if (!node) return 0;\n\n        // Clamp negative arms to 0 — never worth including them.\n        int left  = max(0, dfs(node->left));\n        int right = max(0, dfs(node->right));\n\n        // Path that bends here (cannot extend further upward).\n        ans = max(ans, left + node->val + right);\n\n        // Best arm we can pass to the parent (only one side).\n        return node->val + max(left, right);\n    }\n\npublic:\n    int maxPathSum(TreeNode* root) {\n        dfs(root);\n        return ans;\n    }\n};",
