    approach: "- **Key insight:** Any 'O' connected (4-directionally) to a border cell can never be surrounded, so only interior 'O's that have no path to the border should flip.\n- Start a BFS/DFS from every 'O' on the four edges, marking all reachable 'O's as safe (temporary sentinel).\n- After the traversal, any unmarked 'O' is truly surrounded — flip it to 'X'; restore sentinel cells back to 'O'.\n- This runs in a single BFS pass plus one linear scan, touching each cell at most twice.",
    code: "#include <vector>\n#include <queue>\nusing namespace std;\n\nclass Solution {\npublic:\n    void solve(vector<vector<char>>& board) {\n        const int m = board.size();\n        const int n = board[0].size();\n        const int dirs[4][2] = {{-1,0},{1,0},{0,-1},{0,1}};\n\n        // BFS helper: mark all 'O' cells reachable from (r,c) with a sentinel\n        auto bfs = [&](int r, int c) {\n            if (board[r][c] != 'O') return;\n            queue<pair<int,int>> q;\n            board[r][c] = '#';  // sentinel = safe\n            q.push({r, c});\n            while (!q.empty()) {\n                auto [x, y] = q.front(); q.pop();\n                for (auto& d : dirs) {\n                    int nx = x + d[0], ny = y + d[1];\n                    if (nx >= 0 && nx < m && ny >= 0 && ny < n && board[nx][ny] == 'O') {\n                        board[nx][ny] = '#';\n                        q.push({nx, ny});\n                    }\n                }\n            }\n        };\n\n        // Seed BFS from all border 'O' cells\n        for (int j = 0; j < n; ++j) { bfs(0, j);   bfs(m-1, j); }\n        for (int i = 1; i < m-1; ++i) { bfs(i, 0); bfs(i, n-1); }\n\n        // Final pass: flip surrounded 'O' -> 'X', restore sentinels -> 'O'\n        for (auto& row : board)\n            for (char& c : row)\n                c = (c == '#') ? 'O' : (c == 'O') ? 'X' : c;\n    }\n};\n",
