    approach: "- Use a **doubly-linked list** to maintain recency order: the node nearest the tail is most-recently used, nearest the head is least-recently used.\n- Use an **unordered_map** mapping each key to its list node for O(1) lookup.\n- On every `get` or `put`, move the accessed/inserted node to the tail (most-recent position).\n- On overflow, evict the node at the head (least-recent position) and erase it from the map.",
    code: "#include <unordered_map>\nusing namespace std;\n\nclass LRUCache {\n    struct Node {\n        int key, val;\n        Node *prev, *next;\n        Node(int k, int v) : key(k), val(v), prev(nullptr), next(nullptr) {}\n    };\n\n    int capacity_;\n    unordered_map<int, Node*> map_;  // key -> node\n    Node* head_;  // dummy LRU sentinel\n    Node* tail_;  // dummy MRU sentinel\n\n    // Detach node from its current position.\n    void unlink(Node* n) {\n        n->prev->next = n->next;\n        n->next->prev = n->prev;\n    }\n\n    // Insert node just before the tail (MRU position).\n    void insertMRU(Node* n) {\n        n->prev = tail_->prev;\n        n->next = tail_;\n        tail_->prev->next = n;\n        tail_->prev = n;\n    }\n\npublic:\n    LRUCache(int capacity) : capacity_(capacity) {\n        head_ = new Node(-1, -1);\n        tail_ = new Node(-1, -1);\n        head_->next = tail_;\n        tail_->prev = head_;\n    }\n\n    ~LRUCache() {\n        for (Node* cur = head_; cur; ) {\n            Node* nxt = cur->next;\n            delete cur;\n            cur = nxt;\n        }\n    }\n\n    int get(int key) {\n        auto it = map_.find(key);\n        if (it == map_.end()) return -1;\n        Node* n = it->second;\n        unlink(n);\n        insertMRU(n);\n        return n->val;\n    }\n\n    void put(int key, int value) {\n        auto it = map_.find(key);\n        if (it != map_.end()) {\n            // Update existing entry and move to MRU.\n            Node* n = it->second;\n            n->val = value;\n            unlink(n);\n            insertMRU(n);\n        } else {\n            // Insert new entry.\n            Node* n = new Node(key, value);\n            map_[key] = n;\n            insertMRU(n);\n            // Evict LRU if over capacity.\n            if ((int)map_.size() > capacity_) {\n                Node* lru = head_->next;\n                unlink(lru);\n                map_.erase(lru->key);\n                delete lru;\n            }\n        }\n    }\n};\n\n/**\n * Your LRUCache object will be instantiated and called as such:\n * LRUCache* obj = new LRUCache(capacity);\n * int param_1 = obj->get(key);\n * obj->put(key, value);\n */",
