    code: "#include <vector>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    int maxProduct(vector<int>& nums) {\n        // Seed all trackers with the first element.\n        int curMax = nums[0];\n        int curMin = nums[0];\n        int result = nums[0];\n\n        for (int i = 1; i < (int)nums.size(); ++i) {\n            int n = nums[i];\n\n            // Multiplying by n may swap which of curMax/curMin is larger,\n            // so compute both candidates before updating either.\n            int candidates[3] = { n, curMax * n, curMin * n };\n            curMax = *max_element(candidates, candidates + 3);\n            curMin = *min_element(candidates, candidates + 3);\n\n            result = max(result, curMax);\n        }\n\n        return result;\n    }\n};\n",
