    code: "#include <vector>\n#include <algorithm>\n#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    int threeSumClosest(vector<int>& nums, int target) {\n        sort(nums.begin(), nums.end());\n\n        int best = INT_MAX;   // will hold the best sum found so far\n        int n = nums.size();\n\n        for (int i = 0; i < n - 2; ++i) {\n            int lo = i + 1, hi = n - 1;\n\n            while (lo < hi) {\n                int sum = nums[i] + nums[lo] + nums[hi];\n\n                // Update best if this sum is strictly closer to target\n                if (best == INT_MAX ||\n                    abs(sum - target) < abs(best - target)) {\n                    best = sum;\n                }\n\n                if (sum == target) return sum;          // Can't do better\n                else if (sum < target) ++lo;            // Need a larger sum\n                else                  --hi;             // Need a smaller sum\n            }\n        }\n\n        return best;\n    }\n};",
