    approach: "- Maintain two heaps: a max-heap for pending buy orders (highest bid on top) and a min-heap for pending sell orders (lowest ask on top).\n- For each incoming buy order, repeatedly match it against the cheapest available sell if that sell price is at most the buy price; for each sell order, match against the highest available buy if that bid is at least the sell price.\n- Partial fills are re-inserted into the appropriate heap with the remaining quantity.\n- After processing all orders, sum every remaining quantity across both heaps under modulo 10^9+7.",
    code: "#include <vector>\n#include <queue>\n#include <utility>\nusing namespace std;\n\nclass Solution {\npublic:\n    int getNumberOfBacklogOrders(vector<vector<int>>& orders) {\n        // max-heap for buy backlog: {price, qty}\n        priority_queue<pair<int,int>> buys;\n        // min-heap for sell backlog: {price, qty}\n        priority_queue<pair<int,int>, vector<pair<int,int>>, greater<pair<int,int>>> sells;\n\n        for (const auto& o : orders) {\n            int price = o[0], qty = o[1], type = o[2];\n\n            if (type == 0) {\n                // Buy order: match against cheapest sell while affordable\n                while (qty > 0 && !sells.empty() && sells.top().first <= price) {\n                    auto [sp, sq] = sells.top(); sells.pop();\n                    int matched = min(qty, sq);\n                    qty -= matched;\n                    if (sq > matched) sells.push({sp, sq - matched});\n                }\n                if (qty > 0) buys.push({price, qty});\n            } else {\n                // Sell order: match against highest buy while bid meets ask\n                while (qty > 0 && !buys.empty() && buys.top().first >= price) {\n                    auto [bp, bq] = buys.top(); buys.pop();\n                    int matched = min(qty, bq);\n                    qty -= matched;\n                    if (bq > matched) buys.push({bp, bq - matched});\n                }\n                if (qty > 0) sells.push({price, qty});\n            }\n        }\n\n        const long long MOD = 1e9 + 7;\n        long long res = 0;\n        while (!buys.empty())  { res = (res + buys.top().second)  % MOD; buys.pop(); }\n        while (!sells.empty()) { res = (res + sells.top().second) % MOD; sells.pop(); }\n        return static_cast<int>(res);\n    }\n};",
