    code: "#include <cstdint>\nusing namespace std;\n\nclass Solution {\npublic:\n    uint32_t reverseBits(uint32_t n) {\n        uint32_t res = 0;\n        for (int i = 0; i < 32; ++i) {\n            // Place the lowest bit of n into mirror position (31-i) of res\n            res |= (n & 1u) << (31 - i);\n            n >>= 1;\n        }\n        return res;\n    }\n};",
