    summary: "Given the root of a binary tree, return the values of the nodes visible when the tree is viewed from the right side — one value per level, specifically the rightmost node at each depth.",
    approach: "- Perform a **BFS (level-order traversal)** using a queue, processing all nodes level by level.\n- After dequeuing every node in a level, the **last node dequeued** is the rightmost visible node; record its value.\n- Enqueue left child before right child so that right children are naturally processed last within each level.\n- This gives exactly one value per depth in O(n) time with no recursion stack overhead.",
    code: "#include <vector>\n#include <queue>\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n};\n\nclass Solution {\npublic:\n    vector<int> rightSideView(TreeNode* root) {\n        vector<int> result;\n        if (!root) return result;\n\n        queue<TreeNode*> q;\n        q.push(root);\n\n        while (!q.empty()) {\n            int levelSize = q.size();\n            int rightmost = 0;\n\n            for (int i = 0; i < levelSize; ++i) {\n                TreeNode* node = q.front();\n                q.pop();\n\n                // Track the last value seen at this level\n                rightmost = node->val;\n\n                // Enqueue children (left first so right is processed last)\n                if (node->left)  q.push(node->left);\n                if (node->right) q.push(node->right);\n            }\n\n            result.push_back(rightmost);\n        }\n\n        return result;\n    }\n};",
