    approach: "- Use a stack initialized with the top-level elements pushed in **reverse order** so the first element sits on top.\n- `hasNext()` peeks at the top of the stack: if it is an integer, return `true`; if it is a list, pop it and push its children in reverse order, then repeat — this lazily flattens one level at a time.\n- `next()` relies on `hasNext()` having already ensured the top is a plain integer, then pops and returns it.\n- Each element is pushed and popped at most once, giving amortized O(1) per operation.",
    code: "#include <vector>\n#include <stack>\nusing namespace std;\n\n// Provided interface — do not implement.\nclass NestedInteger {\npublic:\n    bool isInteger() const;\n    int getInteger() const;\n    const vector<NestedInteger>& getList() const;\n};\n\nclass NestedIterator {\n    stack<NestedInteger> st;\n\n    // Push elements of a list onto the stack in reverse so the\n    // leftmost element ends up on top.\n    void pushReversed(const vector<NestedInteger>& list) {\n        for (int i = (int)list.size() - 1; i >= 0; --i)\n            st.push(list[i]);\n    }\n\npublic:\n    NestedIterator(vector<NestedInteger>& nestedList) {\n        pushReversed(nestedList);\n    }\n\n    // Flatten lazily: keep expanding lists on top until an integer surfaces.\n    bool hasNext() {\n        while (!st.empty()) {\n            if (st.top().isInteger()) return true;\n            // Top is a list — expand one level.\n            vector<NestedInteger> sublist = st.top().getList();\n            st.pop();\n            pushReversed(sublist);\n        }\n        return false;\n    }\n\n    // Caller must invoke hasNext() before next().\n    int next() {\n        int val = st.top().getInteger();\n        st.pop();\n        return val;\n    }\n};\n\n/**\n * Usage:\n *   NestedIterator it(nestedList);\n *   while (it.hasNext()) cout << it.next() << \" \";\n */\n",
    timeComplexity: "O(1) amortized per next() / hasNext() call; O(n) total over all n integers",
