    code: "#include <vector>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    int maxSubArray(vector<int>& nums) {\n        int cur = nums[0];      // best sum of subarray ending here\n        int best = nums[0];     // global best seen so far\n\n        for (int i = 1; i < (int)nums.size(); ++i) {\n            // extend previous subarray or start a new one at i\n            cur = max(cur + nums[i], nums[i]);\n            best = max(best, cur);\n        }\n\n        return best;\n    }\n};",
