    code: "#include <string>\nusing namespace std;\n\nclass Solution {\n    // Expand from center [l, r] and return the number of palindromic substrings found.\n    int expandCount(const string& s, int l, int r) {\n        int count = 0;\n        while (l >= 0 && r < (int)s.size() && s[l] == s[r]) {\n            ++count;\n            --l;\n            ++r;\n        }\n        return count;\n    }\n\npublic:\n    int countSubstrings(string s) {\n        int total = 0;\n        for (int i = 0; i < (int)s.size(); ++i) {\n            total += expandCount(s, i, i);     // odd-length centers\n            total += expandCount(s, i, i + 1); // even-length centers\n        }\n        return total;\n    }\n};",
