    code: "#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    int mySqrt(int x) {\n        // Base cases: sqrt(0)=0, sqrt(1)=1\n        if (x < 2) return x;\n\n        int lo = 1, hi = x / 2;   // answer is always <= x/2 for x >= 4\n        while (lo <= hi) {\n            int mid = lo + (hi - lo) / 2;\n            // Use division to avoid int overflow instead of mid*mid\n            int div = x / mid;\n            if (div == mid) {\n                return mid;        // exact perfect square\n            } else if (div > mid) {\n                lo = mid + 1;      // mid is too small\n            } else {\n                hi = mid - 1;      // mid is too large\n            }\n        }\n        // hi is the largest integer with hi*hi <= x\n        return hi;\n    }\n};\n",
