    code: "#include <vector>\nusing namespace std;\n\nclass Solution {\npublic:\n    int climbStairs(int n) {\n        if (n <= 2) return n;\n\n        int prev2 = 1; // ways to reach step 1\n        int prev1 = 2; // ways to reach step 2\n\n        for (int i = 3; i <= n; ++i) {\n            int curr = prev1 + prev2; // Fibonacci-style recurrence\n            prev2 = prev1;\n            prev1 = curr;\n        }\n\n        return prev1;\n    }\n};\n",
