    code: "#include <vector>\n#include <stack>\nusing namespace std;\n\nclass Solution {\npublic:\n    vector<int> dailyTemperatures(vector<int>& temperatures) {\n        int n = temperatures.size();\n        vector<int> result(n, 0);\n        // Stack holds indices of days awaiting a warmer future day.\n        // Invariant: temperatures at stacked indices are in non-increasing order.\n        stack<int> mono;\n\n        for (int i = 0; i < n; ++i) {\n            // Current day is warmer than days on the stack — resolve their wait.\n            while (!mono.empty() && temperatures[mono.top()] < temperatures[i]) {\n                result[mono.top()] = i - mono.top();\n                mono.pop();\n            }\n            mono.push(i);\n        }\n        // Remaining indices never found a warmer day; result stays 0.\n        return result;\n    }\n};\n",
