    code: "#include <string>\nusing namespace std;\n\nclass Solution {\npublic:\n    int numDecodings(const string& s) {\n        if (s.empty() || s[0] == '0') return 0;\n\n        // prev2 = dp[i-2], prev1 = dp[i-1]\n        // Base: dp[0] = 1 (empty prefix), dp[1] = 1 (first char already validated)\n        int prev2 = 1, prev1 = 1;\n\n        for (int i = 1; i < (int)s.size(); ++i) {\n            int cur = 0;\n\n            // Single-digit decode: valid if current char is not '0'\n            if (s[i] != '0')\n                cur += prev1;\n\n            // Two-digit decode: valid if the pair is in [10, 26]\n            int twoDigit = (s[i - 1] - '0') * 10 + (s[i] - '0');\n            if (twoDigit >= 10 && twoDigit <= 26)\n                cur += prev2;\n\n            prev2 = prev1;\n            prev1 = cur;\n        }\n\n        return prev1;\n    }\n};\n",
