    approach: "- **Multi-source BFS**: seed the queue with all initially-rotten oranges simultaneously so spreading propagates in parallel from every rotten cell, exactly modeling the one-minute-per-wave constraint.\n- Count fresh oranges upfront; each time BFS infects a neighbor, decrement the counter so a final check detects isolated fresh oranges.\n- Track elapsed time by counting completed BFS levels (waves), incrementing only when a wave actually produced new rotten oranges.\n- If fresh count is non-zero after BFS exhausts, return -1; otherwise return the elapsed minutes.",
    code: "#include <vector>\n#include <queue>\nusing namespace std;\n\nclass Solution {\npublic:\n    int orangesRotting(vector<vector<int>>& grid) {\n        int rows = grid.size(), cols = grid[0].size();\n        queue<pair<int,int>> q;\n        int fresh = 0;\n\n        // Seed queue with all rotten oranges; count fresh ones.\n        for (int r = 0; r < rows; ++r)\n            for (int c = 0; c < cols; ++c)\n                if (grid[r][c] == 2) q.push({r, c});\n                else if (grid[r][c] == 1) ++fresh;\n\n        if (fresh == 0) return 0;  // nothing to rot\n\n        const int dirs[4][2] = {{0,1},{0,-1},{1,0},{-1,0}};\n        int minutes = 0;\n\n        // BFS level-by-level; each level = one minute.\n        while (!q.empty() && fresh > 0) {\n            int sz = q.size();\n            ++minutes;\n            while (sz--) {\n                auto [r, c] = q.front(); q.pop();\n                for (auto& d : dirs) {\n                    int nr = r + d[0], nc = c + d[1];\n                    if (nr >= 0 && nr < rows && nc >= 0 && nc < cols\n                            && grid[nr][nc] == 1) {\n                        grid[nr][nc] = 2;  // mark rotten in-place (no extra visited set needed)\n                        --fresh;\n                        q.push({nr, nc});\n                    }\n                }\n            }\n        }\n\n        return fresh == 0 ? minutes : -1;\n    }\n};\n",
